m(\psi)_\mathcal{I} &= \{|\Psi\rangle \in \mathcal{H} \otimes \mathcal{H} \mid \langle\Psi|\Psi\rangle = 1\} \\
m(\psi)_\mathcal{X} &= \{\Psi: \mathcal{M} \rightarrow \mathcal{X} \mid \Psi \text{ encodes complete deterministic evolution}\}
\end{align}

\subsection{Key Results}
\begin{align}
[\Psi^{-1}(\phi_e)](\mathcal{X}) &: \text{Fully deterministic} \\
[\Psi^{-1}(\phi_e)](\mathcal{O}) &: \text{Appears indeterministic due to } \pi_\mathcal{O} \\
